(38, 'email_notification', '{\"append_date_to_subject\":\"enabled\",\"email_queue\":\"disabed\",\"notifications\":{\"deposit\":{\"status\":\"enabled\",\"tip\":\"If this is enabled, users will get email notification when they make deposits or when their deposit status changes.\",\"warning\":null},\"email_verification\":{\"status\":\"enabled\",\"tip\":\"If this is enabled, users will get email notification when they register.\",\"warning\":\"If you have enabled email verification in the security setting and disabled this notification, users won\'t be able to sign up as no verification link or code will be sent.\"},\"investment\":{\"status\":\"enabled\",\"tip\":\"If this is enabled, users will get email notification when they make investments or when their investment status changes\",\"warning\":null},\"kyc\":{\"status\":\"enabled\",\"tip\":\"If this is enabled, users will get email notification when they carry out KYC verification or when their KYC status changes.\",\"warning\":null},\"otp_verification\":{\"status\":\"enabled\",\"tip\":\"If this is enabled, users will get email notification when they make attempt any action that requires an OTP code.\",\"warning\":\"If you have enabled OTP verification in the security setting and disabled this notification, users won\'t be able to login or carryout any action that requires otp verification as no OTP code will be sent.\"},\"referral\":{\"status\":\"enabled\",\"tip\":\"If this is enabled, users will get email notification when someone sign up with their referral link or code.\",\"warning\":null},\"transaction\":{\"status\":\"enabled\",\"tip\":\"If this is enabled, users will get email notification when any transaction occurs on their account.\",\"warning\":\"Sending too many emails can trigger email quota limit, blacklisting or spam. Consult your hosting provider.\"},\"welcome\":{\"status\":\"enabled\",\"tip\":\"If this is enabled, users will get email notification when their sign up is completed.\",\"warning\":null},\"stock\":{\"status\":\"enabled\",\"tip\":\"If this is enabled, users will get email notification when they purchase or sell stock.\",\"warning\":null},\"etf\":{\"status\":\"enabled\",\"tip\":\"If this is enabled, users will get email notification when they purchase or sell ETF.\",\"warning\":null},\"withdrawal\":{\"status\":\"enabled\",\"tip\":\"If this is enabled, users will get email notification when they withdraw or when their withdrawal status changes.\",\"warning\":null},\"account_ban\":{\"status\":\"enabled\",\"tip\":\"If this is enabled, users will get email notification when their account is banned or unbanned.\",\"warning\":null}}}', '2026-02-24 06:19:05', '2026-02-24 06:19:05'),
